import requests

def test_getapistreamslive():
    base_url = "http://localhost:3001"
    url = f"{base_url}/api/streams?status=live&limit=20"
    headers = {
        "Accept": "application/json"
    }
    try:
        response = requests.get(url, headers=headers, timeout=30)
        response.raise_for_status()
    except requests.exceptions.RequestException as e:
        assert False, f"Request failed: {e}"
    else:
        assert response.status_code == 200, f"Expected status 200, got {response.status_code}"
        try:
            data = response.json()
        except ValueError:
            assert False, "Response is not valid JSON"

        # Response should be a dict containing a 'streams' key with a list
        assert isinstance(data, dict), f"Expected response JSON to be a dict, got {type(data)}"
        assert 'streams' in data, "Response JSON missing 'streams' key"
        assert isinstance(data['streams'], list), f"Expected 'streams' to be a list, got {type(data['streams'])}"

test_getapistreamslive()

