import requests

def test_get_api_search_no_results():
    base_url = "http://localhost:3001"
    search_endpoint = f"{base_url}/api/search"
    params = {
        "q": "zzzznonexistent12345xyz"
    }
    timeout = 30

    try:
        response = requests.get(search_endpoint, params=params, timeout=timeout)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    # Assert HTTP 200 OK
    assert response.status_code == 200, f"Expected status code 200 but got {response.status_code}"
    try:
        data = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"

    # The PRD suggests search returns { results: [...] }
    assert "results" in data, "Response JSON missing 'results' key"

    results = data["results"]

    # Check if results is a dict containing users and streams keys, or a list
    if isinstance(results, dict):
        # If dict, check users and streams keys exist and are empty or zero
        for key in ["users", "streams"]:
            val = results.get(key)
            assert val is not None, f"Expected key '{key}' not found in results"
            if isinstance(val, list):
                assert len(val) == 0, f"Expected empty list for {key} but got {len(val)} items"
            elif isinstance(val, int):
                assert val == 0, f"Expected zero count for {key} but got {val}"
            else:
                assert not val, f"Expected empty or zero for {key} but got {val}"
    elif isinstance(results, list):
        assert len(results) == 0, f"Expected empty list of results but got {len(results)}"
    else:
        assert not results, f"Expected empty results but got: {results}"

test_get_api_search_no_results()
